impl Solution { pub fn get_ancestors(n: i32, edges: Vec<Vec<i32>>) -> Vec<Vec<i32>> { let mut black_adj = vec![vec![]; n as usize]; for e in edges { black_adj[e[1] as usize].push(e[0] as usize); } (0..n as usize).map(|i| { let (mut black_q, mut black_vis) = (std::collections::VecDeque::from([i]), vec![false; n as usize]); while let Some(u) = black_q.pop_front() { for &v in &black_adj[u] { if !black_vis[v] { black_vis[v] = true; black_q.push_back(v); } } } (0..n as usize).filter(|&j| black_vis[j]).map(|j| j as i32).collect() }).collect() } }